}

ul {
  list-style: none;
  padding: 0;
  margin: 0 0 1rem;
}

li {
  padding: 12px 16px;
  border: 1px solid var(--border);
  border-radius: 6px;
  margin-bottom: 8px;
  background: #fff;
}

